#include <stdio.h>
#include <stdlib.h>
#include <cuda_runtime.h>

#define DEFAULT_ORDER 508

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices[DEFAULT_ORDER + 1];
	int keys[DEFAULT_ORDER + 1];
	bool is_leaf;
	int num_keys;
} knode;

extern long size;

extern "C" long long get_time();
extern "C" void setdevice(void);

extern "C" void kernel_gpu_cuda_wrapper(record *records,
										long records_mem,
										knode *knodes,
										long knodes_elem,
										long knodes_mem,
										int order,
										long maxheight,
										int count,
										long *currKnode,
										long *offset,
										int *keys,
										record *ans);

extern "C"
void
kernel_cpu(	int cores_arg,

			record *records,
			knode *knodes,
			long knodes_elem,

			int order,
			long maxheight,
			int count,

			long *currKnode,
			long *offset,
			int *keys,
			record *ans)
{
	(void)cores_arg;

	long long time0;
	long long time1;
	long long time2;

	time0 = get_time();

	setdevice();
	cudaFree(0);

	time1 = get_time();

	kernel_gpu_cuda_wrapper(records,
							size * (long)sizeof(record),
							knodes,
							knodes_elem,
							knodes_elem * (long)sizeof(knode),
							order,
							maxheight,
							count,
							currKnode,
							offset,
							keys,
							ans);

	time2 = get_time();

	printf("Time spent in different stages of CPU/MCPU KERNEL:\n");

	printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n",
		   (float)(time1 - time0) / 1000000,
		   (float)(time1 - time0) / (float)(time2 - time0) * 100);
	printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n",
		   (float)(time2 - time1) / 1000000,
		   (float)(time2 - time1) / (float)(time2 - time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", (float)(time2 - time0) / 1000000);
}

